option.value:
/* ============================================================
   Warm Coffee Markdown Theme for IntelliJ
   Dark amber/coffee palette · Serif · ~700px reading width
   ============================================================ */

body {
    background-color: #2b201a;
    color: #e8d9c4;
    font-family: "Iowan Old Style", "Charter", "Georgia", "Cambria", serif;
    font-size: 17px;
    line-height: 1.75;
    max-width: 700px;
    margin: 0 auto;
    padding: 3.5rem 2.5rem 5rem 2.5rem;
    -webkit-font-smoothing: antialiased;
    text-rendering: optimizeLegibility;
}

/* ---------- Headings ---------- */
h1, h2, h3, h4, h5, h6 {
    color: #e8b87d;
    font-family: "Iowan Old Style", "Charter", "Georgia", serif;
    font-weight: 700;
    line-height: 1.3;
    margin-top: 2em;
    margin-bottom: 0.6em;
    letter-spacing: -0.01em;
}

h1 {
    font-size: 2.2em;
    color: #f0b86e;
    border-bottom: 1px solid #5c4434;
    padding-bottom: 0.3em;
    margin-top: 0.5em;
}

h2 {
    font-size: 1.7em;
    border-bottom: 1px solid #4a3528;
    padding-bottom: 0.25em;
}

h3 { font-size: 1.4em; }
h4 { font-size: 1.2em; color: #d4a574; }
h5, h6 { font-size: 1em; color: #c4956a; }

/* ---------- Paragraphs ---------- */
p {
    margin: 0 0 1.2em 0;
}

/* ---------- Links ---------- */
a {
    color: #f0b86e;
    text-decoration: none;
    border-bottom: 1px dotted #c4956a;
    transition: all 0.2s ease;
}

a:hover {
    color: #ffd194;
    border-bottom: 1px solid #ffd194;
}

/* ---------- Emphasis ---------- */
strong, b {
    color: #f5e1c4;
    font-weight: 700;
}

em, i {
    color: #d4b896;
    font-style: italic;
}

/* ---------- Lists ---------- */
ul, ol {
    margin: 0 0 1.3em 0;
    padding-left: 1.8em;
}

li {
    margin-bottom: 0.4em;
}

ul li::marker,
ol li::marker {
    color: #c87f3a;
}

li > ul,
li > ol {
    margin-top: 0.4em;
    margin-bottom: 0;
}

/* ---------- Blockquotes ---------- */
blockquote {
    margin: 1.5em 0;
    padding: 0.9em 1.5em;
    border-left: 4px solid #c87f3a;
    background-color: #3a2a20;
    color: #d4b896;
    font-style: italic;
    border-radius: 0 6px 6px 0;
}

blockquote p:last-child {
    margin-bottom: 0;
}

/* ---------- Inline code ---------- */
code {
    background-color: #3a2a20;
    color: #f0c896;
    padding: 0.15em 0.45em;
    border-radius: 4px;
    font-family: "JetBrains Mono", "Fira Code", "Consolas", monospace;
    font-size: 0.88em;
    border: 1px solid #4a3528;
}

/* ---------- Code blocks ---------- */
pre {
    background-color: #1f1612;
    padding: 1.2em 1.4em;
    border-radius: 8px;
    overflow-x: auto;
    margin: 1.6em 0;
    border: 1px solid #4a3528;
    line-height: 1.55;
}

pre code {
    background: none;
    border: none;
    padding: 0;
    color: #e8d9c4;
    font-size: 0.9em;
}

/* ---------- Tables ---------- */
table {
    border-collapse: collapse;
    margin: 1.8em 0;
    width: 100%;
    background-color: #34261e;
    border-radius: 6px;
    overflow: hidden;
    font-size: 0.95em;
}

th, td {
    padding: 0.75em 1em;
    text-align: left;
    border-bottom: 1px solid #4a3528;
}

th {
    background-color: #3a2a20;
    color: #f0b86e;
    font-weight: 700;
    letter-spacing: 0.02em;
}

tr:last-child td {
    border-bottom: none;
}

tr:hover {
    background-color: #3a2a20;
}

/* ---------- Horizontal rule ---------- */
hr {
    border: none;
    border-top: 1px solid #5c4434;
    margin: 2.8em 0;
}

/* ---------- Images ---------- */
img {
    max-width: 100%;
    height: auto;
    border-radius: 6px;
    margin: 1.2em 0;
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.35);
}

/* ---------- Task lists ---------- */
input[type="checkbox"] {
    accent-color: #c87f3a;
    margin-right: 0.5em;
}

/* ---------- Selection ---------- */
::selection {
    background-color: #c87f3a;
    color: #1f1612;
}

/* ---------- Scrollbar (for code blocks) ---------- */
pre::-webkit-scrollbar {
    height: 8px;
}

pre::-webkit-scrollbar-track {
    background: #2b201a;
}

pre::-webkit-scrollbar-thumb {
    background: #5c4434;
    border-radius: 4px;
}

pre::-webkit-scrollbar-thumb:hover {
    background: #7a5c44;
}
